import{_ as e,o as i,c as l,ag as o}from"./chunks/framework.ByAj6Cie.js";const h=JSON.parse('{"title":"Charolas Portacables (Cable Trays)","description":"","frontmatter":{},"headers":[],"relativePath":"es/cables/installation/trays.md","filePath":"es/cables/installation/trays.md"}'),r={name:"es/cables/installation/trays.md"};function s(n,a,c,t,d,p){return i(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="charolas-portacables-cable-trays" tabindex="-1">Charolas Portacables (Cable Trays) <a class="header-anchor" href="#charolas-portacables-cable-trays" aria-label="Permalink to &quot;Charolas Portacables (Cable Trays)&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción General <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción General&quot;">​</a></h2><p>Las charolas portacables son sistemas de soporte utilizados para canalizar y organizar cables en instalaciones industriales. Proporcionan una estructura abierta que permite colocar, soportar y gestionar cables a lo largo de trayectorias definidas.</p><p>A diferencia del conduit, las charolas no encierran completamente los cables, lo que permite una mejor disipación de calor y un acceso más sencillo.</p><hr><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Las charolas portacables se utilizan para:</p><ul><li>Soportar y organizar múltiples tendidos de cables</li><li>Proporcionar rutas estructuradas dentro de instalaciones</li><li>Facilitar la instalación, inspección y mantenimiento</li><li>Mejorar la disipación térmica en comparación con sistemas cerrados</li><li>Permitir una gestión de cables flexible y escalable</li></ul><hr><h2 id="como-funciona" tabindex="-1">Cómo Funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo Funciona&quot;">​</a></h2><p>Los cables se colocan sobre o dentro de estructuras de charola instaladas en muros, techos o soportes estructurales.</p><p>El diseño abierto:</p><ul><li>Permite la circulación de aire para enfriamiento</li><li>Facilita la instalación y retiro de cables</li><li>Hace más sencilla la inspección y modificación</li></ul><p>Las charolas suelen instalarse en rutas continuas, formando una red que guía los cables a lo largo de la instalación.</p><hr><h2 id="tipos-comunes-de-charolas" tabindex="-1">Tipos Comunes de Charolas <a class="header-anchor" href="#tipos-comunes-de-charolas" aria-label="Permalink to &quot;Tipos Comunes de Charolas&quot;">​</a></h2><h3 id="charola-tipo-escalera-ladder" tabindex="-1">Charola Tipo Escalera (Ladder) <a class="header-anchor" href="#charola-tipo-escalera-ladder" aria-label="Permalink to &quot;Charola Tipo Escalera (Ladder)&quot;">​</a></h3><ul><li>Dos rieles laterales unidos por peldaños</li><li>Alta resistencia mecánica</li></ul><p><strong>Aplicaciones:</strong></p><ul><li>Cables de potencia</li><li>Recorridos largos horizontales</li></ul><hr><h3 id="charola-perforada-ventilada" tabindex="-1">Charola Perforada (Ventilada) <a class="header-anchor" href="#charola-perforada-ventilada" aria-label="Permalink to &quot;Charola Perforada (Ventilada)&quot;">​</a></h3><ul><li>Base sólida con perforaciones para ventilación</li><li>Soporte moderado con flujo de aire</li></ul><p><strong>Aplicaciones:</strong></p><ul><li>Cables de control e instrumentación</li><li>Instalaciones de uso general</li></ul><hr><h3 id="charola-de-fondo-solido" tabindex="-1">Charola de Fondo Sólido <a class="header-anchor" href="#charola-de-fondo-solido" aria-label="Permalink to &quot;Charola de Fondo Sólido&quot;">​</a></h3><ul><li>Base completamente cerrada (sin ventilación)</li><li>Máxima protección</li></ul><p><strong>Aplicaciones:</strong></p><ul><li>Cables sensibles que requieren protección adicional</li><li>Entornos con caída de objetos o suciedad</li></ul><hr><h3 id="charola-tipo-malla-canastilla" tabindex="-1">Charola Tipo Malla (Canastilla) <a class="header-anchor" href="#charola-tipo-malla-canastilla" aria-label="Permalink to &quot;Charola Tipo Malla (Canastilla)&quot;">​</a></h3><ul><li>Estructura ligera tipo malla</li><li>Flexible y fácil de instalar</li></ul><p><strong>Aplicaciones:</strong></p><ul><li>Cables de comunicación y datos</li><li>Instalaciones de baja carga</li></ul><hr><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las charolas portacables se utilizan en:</p><ul><li>Plantas industriales y fábricas</li><li>Sistemas de distribución eléctrica</li><li>Sistemas de control y automatización</li><li>Redes de datos y comunicación</li></ul><hr><h2 id="consideraciones-clave" tabindex="-1">Consideraciones Clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones Clave&quot;">​</a></h2><p>Al seleccionar y diseñar sistemas de charolas:</p><ul><li><strong>Tipo y peso del cable:</strong> determina la resistencia requerida</li><li><strong>Disipación térmica:</strong> diseños abiertos mejoran el enfriamiento</li><li><strong>Condiciones ambientales:</strong> corrosión, humedad, polvo</li><li><strong>Accesibilidad:</strong> facilidad de instalación y mantenimiento</li><li><strong>Separación de cables:</strong> evitar interferencias entre potencia y señales</li><li><strong>Espaciamiento de soportes:</strong> evitar deformaciones o flechas excesivas</li></ul><hr><h2 id="notas-practicas" tabindex="-1">Notas Prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas Prácticas&quot;">​</a></h2><ul><li>Las charolas suelen preferirse sobre conduit en instalaciones grandes por su flexibilidad y accesibilidad.</li><li>Sobrecargar una charola puede causar fallas mecánicas y problemas térmicos.</li><li>Es fundamental separar cables de potencia y señales dentro de la charola para evitar ruido eléctrico.</li><li>Los sistemas deben diseñarse considerando expansiones futuras.</li><li>Puede ser necesario aterrizar charolas metálicas según normas y prácticas de instalación.</li></ul>',46)])])}const m=e(r,[["render",s]]);export{h as __pageData,m as default};
